    for p in bpe(t): ids.append(enc[p])
print("input ids",ids)
# load weights logical order
mm=np.memmap('gpt2-124M.ckpt',dtype='<f4',mode='r')
off=0
def take(*shape):
    global off; n=int(np.prod(shape)); a=np.array(mm[off:off+n]).reshape(shape); off+=n; return a
wte=take(50257,768); wpe=take(1024,768)
blocks=[]
for i in range(12):
    d={}
    d['ln1_g']=take(768); d['ln1_b']=take(768)
    d['aw']=take(768,2304); d['ab']=take(2304)
    d['pw']=take(768,768); d['pb']=take(768)
    d['ln2_g']=take(768); d['ln2_b']=take(768)
    d['fw']=take(768,3072); d['fb']=take(3072)
    d['mw']=take(3072,768); d['mb']=take(768)
    blocks.append(d)
lnf_g=take(768); lnf_b=take(768)
def ln(x,g,b):
    m=x.mean(-1,keepdims=True); v=x.var(-1,keepdims=True)
    return (x-m)/np.sqrt(v+1e-5)*g+b
def gelu(x):
    return 0.5*x*(1+np.tanh(np.sqrt(2/np.pi)*(x+0.044715*x**3)))
def softmax(x):
    x=x-x.max(-1,keepdims=True); e=np.exp(x); return e/e.sum(-1,keepdims=True)
